sql:
SELECT AVG(avg_battery_range) AS average_battery_range
FROM electric_vehicle_sales
WHERE year >= 2012;

SELECT year, tot_sales, AVG(avg_battery_range) AS avg_battery_range
FROM electric_vehicle_sales
GROUP BY year, tot_sales;

SELECT avg_fuel_efficiency
FROM gas_prices
WHERE year = 2012;

SELECT year, (ev_sales + phev_sales) AS total_electric_vehicle_sales
FROM electric_vehicle_sales
ORDER BY year ASC;

SELECT SUM(ev_sales) AS total_ev_sales, SUM(phev_sales) AS total_phev_sales
FROM electric_vehicle_sales
WHERE year = 2012;

SELECT year
FROM electric_vehicle_sales
ORDER BY year ASC;

SELECT year, avg_battery_range
FROM electric_vehicle_sales
WHERE tot_prod > 5000000 AND avg_battery_range > 20;

SELECT SUM(tot_ren_energy) AS total_renewable_energy
FROM renewable_energy
WHERE year = 2011;

SELECT year
FROM electric_vehicle_sales
WHERE ev_sales = (SELECT MAX(ev_sales) FROM electric_vehicle_sales);
